let text = '⚡ **TU FOCUS DE HOY**\n\n';
if($input.all().length === 0) {
  text += 'No hay tareas activas en el sistema.';
} else {
  let item = $input.all()[0];
  text += `🎯 **[#${item.json.id}] ${item.json.titulo}**\n🔥 Prioridad: ` + "`" + item.json.prioridad + "`\n" + `⚙️ Tipo: ` + "`" + item.json.tipo_tarea + "`";
}
return { json: { text: text, task_id: $input.all().length > 0 ? $input.all()[0].json.id : null } };

let text = '🌅 **PLANIFICACIÓN DE HOY**\n\n🔥 Prioridad Alta:\n';
for(let item of $input.all()) {
  text += `🔹 [#${item.json.id}] ${item.json.titulo}\n`;
}
text += '\n*(Usa /focus para atacar la primera)*';
return { json: { text: text } };
